169ÔåÆ### 4. i18n ÔÇö i18next + i18nRune
170ÔåÆ
171ÔåÆLazy-Loading-Architektur mit custom Svelte 5 Rune:
172ÔåÆ
173ÔåÆ```typescript
174ÔåÆ// src/lib/i18n/i18n.svelte.ts
175ÔåÆimport i18next from 'i18next';
176ÔåÆ
177ÔåÆexport class I18nRune {
178ÔåÆ	locale = $state<SupportedLocale>('de');
179ÔåÆ	ready = $state(false);
180ÔåÆ
181ÔåÆ	async init() {
182ÔåÆ		const de = await fetch('/locales/de.json').then((r) => r.json());
183ÔåÆ		await i18next.init({ lng: 'de', resources: { de: { translation: de } } });
184ÔåÆ		this.ready = true;
185ÔåÆ	}
186ÔåÆ
187ÔåÆ	async changeLocale(lang: SupportedLocale) {
188ÔåÆ		if (!i18next.hasResourceBundle(lang, 'translation')) {
189ÔåÆ			const data = await fetch(`/locales/${lang}.json`).then((r) => r.json());
190ÔåÆ			i18next.addResourceBundle(lang, 'translation', data);
191ÔåÆ		}
192ÔåÆ		await i18next.changeLanguage(lang);
193ÔåÆ		this.locale = lang;
194ÔåÆ	}
195ÔåÆ
196ÔåÆ	t(key: string, params?: Record<string, unknown>): string {
197ÔåÆ		return i18next.t(key, params) ?? key;
198ÔåÆ	}
199ÔåÆ}
200ÔåÆ```
201ÔåÆ
